#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1 

void run(int argc, char** argv);

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9
int pyramid_height;

void
init(int argc, char** argv)
{
	if(argc==4){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
                pyramid_height=atoi(argv[3]);
	}else{
                printf("Usage: dynproc row_len col_len pyramid_height\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *wall,
                int *src,
                int *results,
                int cols, 
                int rows,
                int startStep,
                int border)
{
    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
    int blockCols = (cols + small_block_cols - 1) / small_block_cols;

    #pragma omp parallel
    {
        int prev[BLOCK_SIZE];
        int result_arr[BLOCK_SIZE];

        #pragma omp for
        for (int bx = 0; bx < blockCols; bx++) {
            int blkX = small_block_cols * bx - border;
            int blkXmax = blkX + BLOCK_SIZE - 1;

            int validXmin = (blkX < 0) ? -blkX : 0;
            int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int xidx = blkX + tx;
                if (IN_RANGE(xidx, 0, cols - 1)) {
                    prev[tx] = src[xidx];
                } else {
                    prev[tx] = 0;
                }
            }

            for (int i = 0; i < iteration; i++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    bool isValid = IN_RANGE(tx, validXmin, validXmax);
                    int W = tx - 1;
                    int E = tx + 1;

                    W = (validXmin > W) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                        int left = prev[W];
                        int up = prev[tx];
                        int right = prev[E];
                        int shortest = MIN(left, up);
                        shortest = MIN(shortest, right);
                        int index = cols * (startStep + i) + blkX + tx;
                        // Fix: ensure index is in range for wall array
                        if (index >= 0 && index < cols * (rows - 1)) {
                            result_arr[tx] = shortest + wall[index];
                        } else {
                            result_arr[tx] = shortest;
                        }
                    } else {
                        result_arr[tx] = prev[tx];
                    }
                }
                // Copy result_arr to prev for next iteration except last
                if (i != iteration - 1) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        prev[tx] = result_arr[tx];
                    }
                }
            }

            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                bool isValid = IN_RANGE(tx, validXmin, validXmax);
                int xidx = blkX + tx;
                if (isValid && IN_RANGE(xidx, 0, cols - 1)) {
                    results[xidx] = result_arr[tx];
                }
            }
        }
    }
}

int calc_path(int *wall, int *result[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{
    int src = 1, dst = 0;
    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;
        int iter = MIN(pyramid_height, rows - t - 1);
        dynproc_kernel(iter, wall, result[src], result[dst], cols, rows, t, borderCols);
    }
    return dst;
}

int main(int argc, char** argv)
{
    run(argc,argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height)*HALO;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*HALO*2;
    int blockCols = cols/smallBlockCol+((0 == cols%smallBlockCol)?0:1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",\
	pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int size = rows*cols;

    int* wall = data + cols; // wall data excluding first row

    int* gpuResult[2];
    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];

    // Initialize gpuResult[0] with first row of data
    for (int i = 0; i < cols; i++) {
        gpuResult[0][i] = data[i];
    }

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(wall, gpuResult, rows, cols, pyramid_height, blockCols, borderCols);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    for (int i = 0; i < cols; i++) {
        result[i] = gpuResult[final_ret][i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;
    printf("\n") ;
    for (int i = 0; i < cols; i++)
            printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] gpuResult[0];
    delete [] gpuResult[1];

    delete [] data;
    delete [] wall;
    delete [] result;

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
